DELETE FROM conquest_map
WHERE member_id      = #{memberId}
  AND trip_place_id  IS NULL
  AND region_id IN (
      SELECT region_id FROM region
      WHERE sido_name        = #{sidoName}
        AND api_sigungu_code IS NULL
  )

mapper.select:
SELECT b.BOOKMARK_ID AS bookmarkId, b.PLACE_ID AS placeId, p.PLACE_NAME AS placeName, p.ADDRESS AS address, p.IMAGE_URL AS imageUrl, p.CATEGORY AS category, b.CREATED_AT AS createdAt FROM BOOKMARK b JOIN PLACE p ON b.PLACE_ID = p.PLACE_ID WHERE b.MEMBER_ID = #{memberId} AND p.IS_ACTIVE = 1
AND p.CATEGORY = #{type}
ORDER BY b.CREATED_AT DESC

SELECT COUNT(*)
FROM   conquest_map
WHERE  member_id = #{memberId}
AND    region_id = #{regionId}

SELECT conquest_map_id
FROM   conquest_map
WHERE  member_id = #{memberId}
AND    region_id = #{regionId}

mapper.delete:
DELETE FROM conquest_map
WHERE member_id = #{memberId}
AND   region_id = #{regionId}

DELETE FROM conquest_map_photo
WHERE  photo_id = #{photoId}
AND    conquest_map_id IN (
           SELECT conquest_map_id
           FROM   conquest_map
           WHERE  member_id = #{memberId}
       )

