UPDATE PLACE_REVIEW
SET RATING     = #{rating},
    CONTENT    = #{content},
    UPDATED_AT = SYSDATE
WHERE REVIEW_ID  = #{reviewId}
  AND MEMBER_ID  = #{memberId}

